import React, { useState, useMemo } from "react";
import { useMsal } from "@azure/msal-react";
import { loginRequest } from "../authConfig";
import { submitQARecord } from "../sharepointService";
import { QA_QUESTIONS } from "../questions";

const CATEGORIES = [...new Set(QA_QUESTIONS.map((q) => q.category))];

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #e8f0fe 0%, #f0f4f8 100%)",
    padding: "24px 16px",
    fontFamily: "Arial, sans-serif",
  },
  card: {
    maxWidth: 860,
    margin: "0 auto",
    background: "#fff",
    borderRadius: 12,
    boxShadow: "0 4px 24px rgba(0,0,0,0.08)",
    overflow: "hidden",
  },
  header: {
    background: "linear-gradient(135deg, #1F5C99 0%, #154073 100%)",
    padding: "28px 32px",
    color: "#fff",
  },
  headerTitle: { margin: 0, fontSize: 24, fontWeight: 700 },
  headerSub: { margin: "6px 0 0", fontSize: 14, color: "#A9C4DE" },
  body: { padding: "28px 32px" },

  row: { display: "flex", gap: 16, marginBottom: 16 },
  col: { flex: 1, display: "flex", flexDirection: "column" },
  label: { fontSize: 13, fontWeight: 600, color: "#444", marginBottom: 6 },
  input: {
    padding: "10px 12px",
    border: "1.5px solid #ddd",
    borderRadius: 8,
    fontSize: 14,
    outline: "none",
    transition: "border-color 0.15s",
  },

  sectionHeader: {
    display: "flex",
    alignItems: "center",
    gap: 10,
    margin: "24px 0 12px",
  },
  sectionPill: {
    background: "#1F5C99",
    color: "#fff",
    fontSize: 11,
    fontWeight: 700,
    padding: "3px 10px",
    borderRadius: 12,
    letterSpacing: 0.5,
    textTransform: "uppercase",
  },
  sectionLine: { flex: 1, height: 1, background: "#e0e8f0" },

  questionRow: {
    display: "flex",
    alignItems: "flex-start",
    gap: 12,
    padding: "10px 12px",
    borderRadius: 8,
    marginBottom: 6,
    transition: "background 0.1s",
  },
  questionNum: {
    width: 28,
    height: 28,
    minWidth: 28,
    borderRadius: "50%",
    background: "#e8f0fe",
    color: "#1F5C99",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: 12,
    fontWeight: 700,
    marginTop: 1,
  },
  questionText: { flex: 1, fontSize: 14, color: "#333", lineHeight: 1.5, paddingTop: 4 },
  toggleGroup: { display: "flex", gap: 6, marginTop: 4 },
  toggleBtn: (selected, variant) => ({
    padding: "5px 16px",
    borderRadius: 20,
    border: "1.5px solid",
    cursor: "pointer",
    fontSize: 13,
    fontWeight: 600,
    transition: "all 0.15s",
    borderColor: variant === "Yes"
      ? (selected ? "#2E7D32" : "#ccc")
      : (selected ? "#C62828" : "#ccc"),
    background: variant === "Yes"
      ? (selected ? "#E8F5E9" : "#fff")
      : (selected ? "#FFEBEE" : "#fff"),
    color: variant === "Yes"
      ? (selected ? "#2E7D32" : "#999")
      : (selected ? "#C62828" : "#999"),
  }),

  scoreBar: {
    margin: "24px 0",
    padding: "16px 20px",
    borderRadius: 10,
    border: "2px solid",
    display: "flex",
    alignItems: "center",
    gap: 20,
  },
  scoreNum: { fontSize: 36, fontWeight: 800, lineHeight: 1 },
  scoreSub: { fontSize: 12, color: "#666", marginTop: 2 },
  scoreBadge: {
    padding: "4px 14px",
    borderRadius: 20,
    fontSize: 13,
    fontWeight: 700,
  },
  progressTrack: {
    flex: 1,
    height: 10,
    background: "#eee",
    borderRadius: 5,
    overflow: "hidden",
  },

  textarea: {
    width: "100%",
    padding: "10px 12px",
    border: "1.5px solid #ddd",
    borderRadius: 8,
    fontSize: 14,
    resize: "vertical",
    minHeight: 90,
    outline: "none",
    fontFamily: "Arial, sans-serif",
    boxSizing: "border-box",
  },

  submitBtn: (disabled) => ({
    display: "block",
    width: "100%",
    padding: "14px",
    marginTop: 24,
    background: disabled ? "#aaa" : "linear-gradient(135deg, #1F5C99, #154073)",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    fontSize: 16,
    fontWeight: 700,
    cursor: disabled ? "not-allowed" : "pointer",
    transition: "opacity 0.2s",
  }),

  successBox: {
    textAlign: "center",
    padding: "48px 32px",
  },
  successCircle: {
    width: 72,
    height: 72,
    borderRadius: "50%",
    background: "#E8F5E9",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    margin: "0 auto 16px",
    fontSize: 36,
  },
  errorBox: {
    background: "#FFEBEE",
    border: "1px solid #FFCDD2",
    borderRadius: 8,
    padding: "12px 16px",
    color: "#C62828",
    fontSize: 14,
    marginTop: 16,
  },
};

function scoreColor(pct) {
  if (pct >= 90) return { border: "#2E7D32", text: "#2E7D32", bar: "#4CAF50", bg: "#F1F8E9" };
  if (pct >= 80) return { border: "#388E3C", text: "#388E3C", bar: "#66BB6A", bg: "#E8F5E9" };
  if (pct >= 70) return { border: "#F57F17", text: "#F57F17", bar: "#FFA726", bg: "#FFF8E1" };
  return { border: "#C62828", text: "#C62828", bar: "#EF5350", bg: "#FFEBEE" };
}

export default function QAForm() {
  const { instance, accounts } = useMsal();

  const initialAnswers = Object.fromEntries(QA_QUESTIONS.map((q) => [q.field, null]));
  const [answers, setAnswers] = useState(initialAnswers);
  const [agentName, setAgentName] = useState("");
  const [evaluatorName, setEvaluatorName] = useState("");
  const [suggestions, setSuggestions] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [error, setError] = useState(null);

  const { totalScore, scorePercent, passFail, answered } = useMemo(() => {
    const yesCount = QA_QUESTIONS.filter((q) => answers[q.field] === "Yes").length;
    const total = yesCount * 5;
    const pct = total;
    return {
      totalScore: total,
      scorePercent: pct,
      passFail: pct >= 80 ? "Pass" : "Fail",
      answered: QA_QUESTIONS.filter((q) => answers[q.field] !== null).length,
    };
  }, [answers]);

  const allAnswered = answered === QA_QUESTIONS.length && agentName.trim() && evaluatorName.trim();
  const colors = scoreColor(scorePercent);

  async function handleSubmit(e) {
    e.preventDefault();
    if (!allAnswered) return;
    setSubmitting(true);
    setError(null);

    try {
      const tokenResponse = await instance.acquireTokenSilent({
        ...loginRequest,
        account: accounts[0],
      });

      await submitQARecord(tokenResponse.accessToken, {
        ...answers,
        AgentName: agentName.trim(),
        EvaluatorName: evaluatorName.trim(),
        SuggestionsForImprovement: suggestions.trim(),
        TotalScore: totalScore,
        ScorePercent: scorePercent,
        PassFail: passFail,
      });

      setSubmitted(true);
    } catch (err) {
      // If silent token acquisition fails, try interactive
      if (err.name === "InteractionRequiredAuthError") {
        try {
          const tokenResponse = await instance.acquireTokenPopup(loginRequest);
          await submitQARecord(tokenResponse.accessToken, {
            ...answers,
            AgentName: agentName.trim(),
            EvaluatorName: evaluatorName.trim(),
            SuggestionsForImprovement: suggestions.trim(),
            TotalScore: totalScore,
            ScorePercent: scorePercent,
            PassFail: passFail,
          });
          setSubmitted(true);
        } catch (popupErr) {
          setError(popupErr.message);
        }
      } else {
        setError(err.message);
      }
    } finally {
      setSubmitting(false);
    }
  }

  function resetForm() {
    setAnswers(initialAnswers);
    setAgentName("");
    setEvaluatorName("");
    setSuggestions("");
    setSubmitted(false);
    setError(null);
  }

  if (submitted) {
    return (
      <div style={styles.page}>
        <div style={styles.card}>
          <div style={styles.header}>
            <h1 style={styles.headerTitle}>Support Quality Assurance</h1>
          </div>
          <div style={styles.successBox}>
            <div style={styles.successCircle}>✅</div>
            <h2 style={{ margin: "0 0 8px", color: "#1F5C99" }}>Screening Submitted</h2>
            <p style={{ color: "#555", margin: "0 0 8px" }}>
              <strong>{agentName}</strong> — evaluated by <strong>{evaluatorName}</strong>
            </p>
            <div
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: 10,
                padding: "10px 24px",
                borderRadius: 10,
                background: colors.bg,
                border: `2px solid ${colors.border}`,
                margin: "12px 0 24px",
              }}
            >
              <span style={{ fontSize: 28, fontWeight: 800, color: colors.text }}>
                {scorePercent}%
              </span>
              <span
                style={{
                  ...styles.scoreBadge,
                  background: colors.border,
                  color: "#fff",
                }}
              >
                {passFail}
              </span>
            </div>
            <br />
            <button
              onClick={resetForm}
              style={{
                padding: "10px 28px",
                background: "#1F5C99",
                color: "#fff",
                border: "none",
                borderRadius: 8,
                fontSize: 14,
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              Start New Screening
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        {/* Header */}
        <div style={styles.header}>
          <h1 style={styles.headerTitle}>Support Quality Assurance</h1>
          <p style={styles.headerSub}>
            20 criteria · 5 points each · 100 points max · Pass threshold: 80%
          </p>
        </div>

        <form onSubmit={handleSubmit} style={styles.body}>
          {/* Agent / Evaluator */}
          <div style={styles.row}>
            <div style={styles.col}>
              <label style={styles.label}>Agent Name *</label>
              <input
                style={styles.input}
                value={agentName}
                onChange={(e) => setAgentName(e.target.value)}
                placeholder="Full name"
                required
              />
            </div>
            <div style={styles.col}>
              <label style={styles.label}>Evaluator Name *</label>
              <input
                style={styles.input}
                value={evaluatorName}
                onChange={(e) => setEvaluatorName(e.target.value)}
                placeholder="Your full name"
                required
              />
            </div>
          </div>

          {/* Live score bar */}
          {answered > 0 && (
            <div style={{ ...styles.scoreBar, borderColor: colors.border, background: colors.bg }}>
              <div>
                <div style={{ ...styles.scoreNum, color: colors.text }}>{scorePercent}%</div>
                <div style={styles.scoreSub}>
                  {totalScore} / 100 pts · {answered}/{QA_QUESTIONS.length} answered
                </div>
              </div>
              <div style={styles.progressTrack}>
                <div
                  style={{
                    height: "100%",
                    width: `${scorePercent}%`,
                    background: colors.bar,
                    borderRadius: 5,
                    transition: "width 0.3s",
                  }}
                />
              </div>
              <span
                style={{
                  ...styles.scoreBadge,
                  background: colors.border,
                  color: "#fff",
                }}
              >
                {passFail}
              </span>
            </div>
          )}

          {/* Questions grouped by category */}
          {CATEGORIES.map((cat) => {
            const qs = QA_QUESTIONS.filter((q) => q.category === cat);
            return (
              <div key={cat}>
                <div style={styles.sectionHeader}>
                  <span style={styles.sectionPill}>{cat}</span>
                  <div style={styles.sectionLine} />
                </div>
                {qs.map((q, idx) => {
                  const globalIdx = QA_QUESTIONS.findIndex((x) => x.field === q.field);
                  const isEven = globalIdx % 2 === 0;
                  return (
                    <div
                      key={q.field}
                      style={{
                        ...styles.questionRow,
                        background: isEven ? "#F8FAFD" : "#fff",
                      }}
                    >
                      <div style={styles.questionNum}>{globalIdx + 1}</div>
                      <div style={{ ...styles.questionText }}>
                        {q.label}
                        <div style={styles.toggleGroup}>
                          {["Yes", "No"].map((opt) => (
                            <button
                              key={opt}
                              type="button"
                              style={styles.toggleBtn(answers[q.field] === opt, opt)}
                              onClick={() =>
                                setAnswers((prev) => ({ ...prev, [q.field]: opt }))
                              }
                            >
                              {opt}
                            </button>
                          ))}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}

          {/* Suggestions */}
          <div style={{ marginTop: 24 }}>
            <label style={styles.label}>Suggestions for Improvement</label>
            <textarea
              style={styles.textarea}
              value={suggestions}
              onChange={(e) => setSuggestions(e.target.value)}
              placeholder="Optional — specific feedback for the agent..."
            />
          </div>

          {/* Error */}
          {error && <div style={styles.errorBox}>⚠️ {error}</div>}

          {/* Unanswered warning */}
          {answered < QA_QUESTIONS.length && answered > 0 && (
            <div
              style={{
                background: "#FFF8E1",
                border: "1px solid #FFE082",
                borderRadius: 8,
                padding: "10px 14px",
                fontSize: 13,
                color: "#795548",
                marginTop: 16,
              }}
            >
              {QA_QUESTIONS.length - answered} question
              {QA_QUESTIONS.length - answered > 1 ? "s" : ""} still need an answer before submitting.
            </div>
          )}

          <button type="submit" style={styles.submitBtn(!allAnswered || submitting)} disabled={!allAnswered || submitting}>
            {submitting ? "Submitting…" : "Submit Screening to SharePoint"}
          </button>
        </form>
      </div>
    </div>
  );
}
